def process_files():
    json_files = sorted(glob.glob(os.path.join(PVO_DIR, '*.json')))
    updated = 0
    skipped = 0
    missing_names = []

    for filepath in json_files:
        filename = os.path.basename(filepath)
        try:
            with open(filepath, 'r', encoding='utf-8') as f:
                data = json.load(f)
        except Exception as e:
            print(f'ERRO lendo {filename}: {e}')
            continue

        pvo_name = data.get('meta', {}).get('pvo_name', '')

        if pvo_name in DESCRIPTIONS:
            data['meta']['description'] = DESCRIPTIONS[pvo_name]
            with open(filepath, 'w', encoding='utf-8') as f:
                json.dump(data, f, ensure_ascii=False, indent=2)
                f.write('\n')
            updated += 1
        else:
            skipped += 1
            missing_names.append(pvo_name)

    print(f'Atualizados: {updated}')
    print(f'Sem descricao: {skipped}')
    if missing_names:
        print(f'Faltando: {missing_names}')

if __name__ == '__main__':
    process_files()
